<!DOCTYPE html>
<html lang="id">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>PalmGuard</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;1,9..40,300&family=IBM+Plex+Mono:wght@400;500;600&display=swap" rel="stylesheet">
<style>
:root{
  --dark:#0b1a0e;
  --darker:#060f08;
  --navy:#0f2214;
  --green:#1DB954;
  --green2:#1ed760;
  --green-dim:rgba(29,185,84,0.12);
  --green-glow:rgba(29,185,84,0.25);
  --white:#fff;
  --muted:#6b8c76;
  --card-bg:#f2f7f3;
  --shadow:0 8px 32px rgba(11,44,20,.13);
  --radius:18px;
  --font-display:'Bebas Neue',cursive;
  --font-body:'DM Sans',sans-serif;
  --font-mono:'IBM Plex Mono',monospace;
  --transition:cubic-bezier(.4,0,.2,1);
}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html{scroll-behavior:smooth}
body{font-family:var(--font-body);color:var(--dark);overflow-x:hidden;background:#fff}
a{text-decoration:none;color:inherit}
ul{list-style:none}
img{display:block;max-width:100%}
::-webkit-scrollbar{display:none}
*{-ms-overflow-style:none;scrollbar-width:none}

/* LOADER */
#loader{position:fixed;inset:0;z-index:9999;background:var(--darker);display:flex;align-items:center;justify-content:center;flex-direction:column;gap:20px;transition:opacity .6s ease,visibility .6s ease}
#loader.hidden{opacity:0;visibility:hidden;pointer-events:none}
.loader-logo{font-family:var(--font-display);font-size:64px;color:var(--green);letter-spacing:10px;animation:pulseText 1.4s ease-in-out infinite alternate;text-shadow:0 0 40px rgba(29,185,84,.4)}
.loader-tagline{font-family:var(--font-mono);font-size:11px;color:rgba(255,255,255,.3);letter-spacing:3px;text-transform:uppercase}
.loader-bar{width:200px;height:2px;background:rgba(255,255,255,.1);border-radius:10px;overflow:hidden}
.loader-fill{height:100%;background:linear-gradient(90deg,var(--green),#56fa8a);border-radius:10px;width:0;animation:loadFill 1.8s var(--transition) forwards}
@keyframes loadFill{from{width:0}to{width:100%}}
@keyframes pulseText{from{opacity:.35;transform:scale(.96)}to{opacity:1;transform:scale(1)}}

/* SCROLL TOP */
.scroll-top{position:fixed;bottom:30px;right:30px;z-index:200;width:46px;height:46px;border-radius:50%;background:var(--dark);color:white;border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;box-shadow:0 8px 24px rgba(11,44,20,.3);opacity:0;transform:translateY(20px);transition:opacity .35s,transform .35s,background .25s}
.scroll-top.visible{opacity:1;transform:translateY(0)}
.scroll-top:hover{background:var(--green)}

/* NAVBAR */
.navbar{position:fixed;top:0;left:0;right:0;z-index:100;display:flex;align-items:center;justify-content:space-between;padding:18px 48px;transition:background .4s,backdrop-filter .4s,box-shadow .4s}
.navbar.scrolled{background:rgba(6,15,8,.88);backdrop-filter:blur(14px);box-shadow:0 2px 24px rgba(0,0,0,.4)}
.nav-logo{display:flex;align-items:center;gap:10px;color:white}
.nav-logo-icon{width:34px;height:34px;background:var(--green-dim);border:1px solid var(--green);border-radius:9px;display:flex;align-items:center;justify-content:center;font-size:16px;box-shadow:0 0 14px var(--green-glow);animation:logoPulse 3s ease infinite}
@keyframes logoPulse{0%,100%{box-shadow:0 0 10px var(--green-glow)}50%{box-shadow:0 0 28px rgba(29,185,84,.5)}}
.nav-logo-text{font-family:var(--font-display);font-size:22px;color:var(--green);letter-spacing:3px}
.nav-links{display:flex;gap:32px}
.nav-links a{color:rgba(255,255,255,.75);font-size:14px;font-weight:400;padding:4px 0;position:relative;transition:color .25s}
.nav-links a::after{content:'';position:absolute;bottom:-2px;left:0;width:0;height:2px;background:var(--green);border-radius:2px;transition:width .3s var(--transition)}
.nav-links a:hover,.nav-links a.active{color:white}
.nav-links a:hover::after,.nav-links a.active::after{width:100%}
.btn-nav-login{display:flex;align-items:center;gap:8px;background:var(--green);color:#000;padding:10px 22px;border-radius:50px;font-size:13px;font-weight:700;font-family:var(--font-body);transition:transform .25s,box-shadow .25s}
.btn-nav-login:hover{transform:translateY(-2px);box-shadow:0 8px 24px var(--green-glow);background:var(--green2)}

/* HERO */
.hero{position:relative;height:100vh;min-height:680px;display:flex;flex-direction:column;justify-content:flex-end;overflow:hidden}
.hero-bg{position:absolute;inset:0}
.hero-img{width:100%;height:115%;object-fit:cover;transform:translateY(0);filter:saturate(0.9)}
.hero-overlay{position:absolute;inset:0;background:linear-gradient(to bottom,rgba(6,15,8,.2) 0%,rgba(6,15,8,.1) 40%,rgba(6,15,8,.82) 100%)}
.hero-overlay::after{content:'';position:absolute;inset:0;background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,.025) 2px,rgba(0,0,0,.025) 4px)}

.hero-big-title{position:absolute;top:50%;left:50%;transform:translate(-50%,-54%);font-family:var(--font-display);font-size:clamp(80px,14vw,190px);color:white;letter-spacing:8px;white-space:nowrap;line-height:1;opacity:0;animation:heroTitleIn 1s .6s var(--transition) forwards;user-select:none;text-align:center;text-shadow:0 0 80px rgba(29,185,84,.15)}
.hero-sub{position:absolute;top:50%;right:5%;transform:translateY(-50%);font-family:var(--font-mono);font-size:clamp(11px,1.6vw,18px);color:rgba(255,255,255,.35);writing-mode:vertical-rl;letter-spacing:6px;opacity:0;animation:fadeUp 1s 1s var(--transition) forwards}
@keyframes heroTitleIn{from{opacity:0;transform:translate(-50%,-62%) scale(.9)}to{opacity:1;transform:translate(-50%,-54%) scale(1)}}

.hero-bottom{position:relative;z-index:2;padding:0 48px 44px;display:flex;align-items:flex-end;justify-content:space-between;gap:20px}
.hero-tagline{color:white;opacity:0;animation:fadeUp .9s .8s var(--transition) forwards}
.hero-tagline h2{font-size:clamp(16px,2.2vw,26px);font-weight:300;line-height:1.4;margin-bottom:14px}
.hero-tagline h2 strong{font-weight:700;display:block;font-size:1.15em}
.hero-stats{display:flex;gap:18px;align-items:center}
.hero-stat{font-size:12px;color:rgba(255,255,255,.6);font-family:var(--font-mono)}
.hero-stat strong{display:block;font-size:18px;color:var(--green);font-weight:700;font-family:var(--font-display);letter-spacing:1px}
.hero-dot{width:4px;height:4px;border-radius:50%;background:rgba(255,255,255,.25)}

.hero-badge-bar{background:rgba(6,15,8,.85);border:1px solid rgba(29,185,84,.25);backdrop-filter:blur(12px);border-radius:14px;padding:14px 20px;display:flex;align-items:center;gap:14px;opacity:0;animation:fadeUp .9s .95s var(--transition) forwards}
.status-dot{width:7px;height:7px;background:var(--green);border-radius:50%;animation:pulse 2s infinite;flex-shrink:0}
@keyframes pulse{0%,100%{opacity:1;box-shadow:0 0 0 0 rgba(29,185,84,.4)}50%{opacity:.6;box-shadow:0 0 0 5px rgba(29,185,84,0)}}
.hero-badge-text{font-family:var(--font-mono);font-size:11px;color:var(--green);letter-spacing:2px;text-transform:uppercase}
.hero-badge-sep{width:1px;height:28px;background:rgba(29,185,84,.2)}
.hero-login-btn{display:flex;align-items:center;gap:8px;background:var(--green);color:#000;padding:10px 20px;border-radius:9px;font-size:13px;font-weight:700;font-family:var(--font-body);transition:all .25s;white-space:nowrap}
.hero-login-btn:hover{background:var(--green2);transform:scale(1.04)}

@keyframes fadeUp{from{opacity:0;transform:translateY(28px)}to{opacity:1;transform:translateY(0)}}

/* SECTIONS */
section{padding:90px 48px}
.section-badge{font-size:11px;font-weight:600;letter-spacing:2.5px;text-transform:uppercase;color:var(--muted);margin-bottom:14px;font-family:var(--font-mono)}
.section-title{font-size:clamp(28px,3.5vw,44px);font-weight:300;line-height:1.2;color:var(--dark)}
.section-title strong{font-weight:700}
.text-center{text-align:center}

/* REVEAL */
.reveal{opacity:0;transform:translateY(40px);transition:opacity .75s var(--transition),transform .75s var(--transition)}
.reveal.visible{opacity:1;transform:translateY(0)}
.reveal-left{opacity:0;transform:translateX(-40px);transition:opacity .75s var(--transition),transform .75s var(--transition)}
.reveal-left.visible{opacity:1;transform:translateX(0)}
.reveal-right{opacity:0;transform:translateX(40px);transition:opacity .75s var(--transition),transform .75s var(--transition)}
.reveal-right.visible{opacity:1;transform:translateX(0)}
.delay-1{transition-delay:.12s!important}
.delay-2{transition-delay:.24s!important}
.delay-3{transition-delay:.36s!important}
.delay-4{transition-delay:.48s!important}

/* FITUR - CTA Style */
.fitur-section{background:#fff;overflow:hidden}
.fitur-block{display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:center;padding:72px 48px;border-bottom:1px solid #daeadd}
.fitur-block:last-child{border-bottom:none}
.fitur-block.reverse{direction:rtl}
.fitur-block.reverse > *{direction:ltr}
.fitur-block-img{border-radius:var(--radius);width:100%;height:320px;object-fit:cover;box-shadow:var(--shadow);transition:transform .5s var(--transition),box-shadow .5s}
.fitur-block-img:hover{transform:scale(1.02);box-shadow:0 24px 56px rgba(11,44,20,.18)}
.fitur-block-badge{display:inline-flex;align-items:center;gap:8px;padding:6px 16px;background:var(--green-dim);border:1px solid rgba(29,185,84,.25);border-radius:50px;font-size:11px;color:var(--green);font-family:var(--font-mono);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:18px}
.fitur-block-title{font-size:clamp(22px,2.8vw,34px);font-weight:700;line-height:1.25;color:var(--dark);margin-bottom:0}
.fitur-tags{display:flex;gap:8px;flex-wrap:wrap;margin-top:20px}
.fitur-tag{display:inline-flex;align-items:center;gap:6px;padding:7px 16px;background:#f2f7f3;border:1.5px solid #daeadd;border-radius:50px;font-size:12.5px;color:var(--dark);font-weight:500;transition:all .25s;cursor:default}
.fitur-tag:hover{background:var(--green);color:#000;border-color:var(--green)}

/* SPONSOR */
.sponsor-section{background:#f7fcf8;border-top:1px solid #daeadd;border-bottom:1px solid #daeadd;padding:72px 48px;text-align:center}
.sponsor-title{font-size:11px;font-weight:600;color:var(--muted);letter-spacing:3px;text-transform:uppercase;margin-bottom:36px;font-family:var(--font-mono)}
.sponsor-grid{display:flex;justify-content:center;align-items:center;gap:60px;flex-wrap:wrap}
.sponsor-grid img{height:60px;opacity:.65;filter:grayscale(30%);transition:.3s}
.sponsor-grid img:hover{opacity:1;filter:grayscale(0%);transform:scale(1.1)}

/* TIM */
.tim-section{background:white;border-top:1px solid #daeadd}
.tim-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:24px;margin-top:48px}
.tim-card{background:#f2f7f3;border:1.5px solid #daeadd;border-radius:var(--radius);padding:36px 24px;text-align:center;transition:all .35s var(--transition);cursor:default}
.tim-card:hover{border-color:var(--green);transform:translateY(-8px);box-shadow:0 20px 44px rgba(11,44,20,.12)}
.tim-avatar-wrap{width:100px;height:100px;border-radius:50%;border:3px solid var(--green);margin:0 auto 18px;overflow:hidden;box-shadow:0 0 20px var(--green-glow);transition:box-shadow .3s}
.tim-card:hover .tim-avatar-wrap{box-shadow:0 0 36px rgba(29,185,84,.4)}
.tim-avatar-wrap img{width:100%;height:100%;object-fit:cover}
.tim-avatar-placeholder{width:100%;height:100%;background:var(--green-dim);display:flex;align-items:center;justify-content:center;font-size:36px}
.tim-name{font-size:15px;font-weight:700;color:var(--dark);margin-bottom:6px}
.tim-role{font-size:12px;color:var(--green);font-family:var(--font-mono);letter-spacing:1px;text-transform:uppercase}

/* LOKASI */
.lokasi-section{background:#f7fcf8;border-top:1px solid #daeadd;display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:center;padding:90px 48px}
.lokasi-map{border-radius:var(--radius);overflow:hidden;border:1.5px solid #daeadd;height:280px;box-shadow:var(--shadow)}
.lokasi-map iframe{width:100%;height:100%;border:none;display:block}
.lokasi-info-badge{display:inline-flex;align-items:center;gap:6px;padding:5px 14px;background:var(--green-dim);border:1px solid rgba(29,185,84,.25);border-radius:50px;font-size:11px;color:var(--green);font-family:var(--font-mono);letter-spacing:1px;margin-bottom:18px}
.lokasi-title{font-size:clamp(22px,2.8vw,34px);font-weight:700;line-height:1.25;margin-bottom:14px;color:var(--dark)}
.lokasi-desc{font-size:14px;color:#5a7a62;line-height:1.8;margin-bottom:24px}
.lokasi-alamat-card{background:white;border:1.5px solid #daeadd;border-radius:12px;padding:16px 20px;display:flex;align-items:flex-start;gap:12px}
.lokasi-pin-icon{font-size:18px;flex-shrink:0;margin-top:2px}
.lokasi-alamat{font-size:13px;color:#5a7a62;line-height:1.7}
.lokasi-alamat strong{display:block;color:var(--dark);font-weight:600;margin-bottom:2px}

/* CTA */
.cta-section{background:white;display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:center;border-top:1px solid #daeadd;padding:90px 48px}
.cta-img{border-radius:var(--radius);width:100%;height:300px;object-fit:cover;box-shadow:var(--shadow);filter:saturate(0.85)}
.cta-title{font-size:clamp(26px,3.2vw,42px);font-weight:700;line-height:1.25;margin-bottom:14px;color:var(--dark)}
.cta-title span{color:var(--green)}
.cta-desc{font-size:14px;color:#5a7a62;line-height:1.8;margin-bottom:28px}
.cta-btn{display:inline-flex;align-items:center;gap:10px;background:var(--dark);color:white;padding:14px 32px;border-radius:50px;font-size:14px;font-weight:700;font-family:var(--font-body);transition:all .25s;border:none;cursor:pointer}
.cta-btn:hover{background:var(--green);color:#000;transform:translateY(-2px);box-shadow:0 10px 32px var(--green-glow)}

/* FOOTER */
footer{background:var(--darker);padding:60px 48px 32px}
.footer-grid{display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:40px;margin-bottom:48px}
.footer-brand{color:var(--green);font-family:var(--font-display);font-size:28px;letter-spacing:4px;margin-bottom:14px;display:flex;align-items:center;gap:10px}
.footer-brand-desc{font-size:13px;color:rgba(255,255,255,.45);line-height:1.8;max-width:280px}
.footer-col-title{font-size:11px;font-weight:600;color:rgba(255,255,255,.35);letter-spacing:2px;text-transform:uppercase;margin-bottom:18px;font-family:var(--font-mono)}
.footer-col a{display:block;font-size:13.5px;color:rgba(255,255,255,.55);margin-bottom:10px;transition:color .2s,padding-left .2s}
.footer-col a:hover{color:var(--green);padding-left:4px}
.social-links{display:flex;gap:10px;margin-top:20px}
.social-link{width:38px;height:38px;border-radius:50%;background:rgba(255,255,255,.07);display:flex;align-items:center;justify-content:center;transition:background .25s,transform .25s;color:rgba(255,255,255,.5);font-size:14px}
.social-link:hover{background:var(--green);color:#000;transform:translateY(-3px)}
.footer-bottom{border-top:1px solid rgba(255,255,255,.07);padding-top:28px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:16px}
.footer-copy{font-size:12px;color:rgba(255,255,255,.25);font-family:var(--font-mono)}

@media(max-width:900px){
  .navbar{padding:16px 20px}
  .nav-links{display:none}
  section,.lokasi-section,.cta-section{padding:60px 20px}
  .sponsor-section{padding:60px 20px}
  .tim-section{padding:60px 20px}
  .hero-bottom{padding:0 20px 28px;flex-direction:column;align-items:flex-start}
  .hero-badge-bar{width:100%}
  .fitur-block,.lokasi-section,.cta-section{grid-template-columns:1fr;gap:32px;padding:60px 20px}
  .fitur-block.reverse{direction:ltr}
  .footer-grid{grid-template-columns:repeat(2,1fr)}
}
@media(max-width:560px){
  .hero-big-title{font-size:72px}
  .footer-grid{grid-template-columns:1fr}
  .tim-grid{grid-template-columns:repeat(2,1fr)}
}
</style>
</head>
<body>

<!-- LOADER -->
<div id="loader">
  <div class="loader-logo">PALMGUARD</div>
  <div class="loader-tagline">SISTEM DETEKSI PENYAKIT DAUN KELAPA SAWIT</div>
  <div class="loader-bar"><div class="loader-fill"></div></div>
</div>

<!-- SCROLL TOP -->
<button class="scroll-top" aria-label="Kembali ke atas">
  <svg width="18" height="18" fill="none" viewBox="0 0 24 24"><path d="M12 19V5M5 12l7-7 7 7" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>
</button>

<!-- NAVBAR -->
<nav class="navbar">
  <div class="nav-logo">
    {{-- <div class="nav-logo-icon">🌿</div> --}}
    <div class="nav-logo-text">PALMGUARD</div>
  </div>
  <ul class="nav-links">
    <li><a href="#" class="active">Home</a></li>
    <li><a href="#fitur">Fitur</a></li>
    <li><a href="#tim">Tim</a></li>
    <li><a href="#lokasi">Lokasi</a></li>
  </ul>
  <a href="{{ route('login') }}" class="btn-nav-login"> Login <svg width="13" height="13" fill="none" viewBox="0 0 24 24"><path d="M5 12h14M13 6l6 6-6 6" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></a>
</nav>

<!-- HERO -->
<section class="hero">
  <div class="hero-bg">
    <img class="hero-img" src="data:image/png;base64," alt="Drone Perkebunan Kelapa Sawit"/>
    <div class="hero-overlay"></div>
  </div>
  <h1 class="hero-big-title">PALMGUARD</h1>
  <span class="hero-sub">CAPSTONE · 2026</span>
  <div class="hero-bottom">
    <div class="hero-tagline">
      <h2>Deteksi Penyakit Daun<br><strong>Kelapa Sawit Lebih Cerdas</strong></h2>
      <div class="hero-stats">
        <div class="hero-stat"><strong><span data-count="4" data-suffix="+">0+</span></strong>Jenis Penyakit</div>
        <div class="hero-dot"></div>
        <div class="hero-stat"><strong><span data-count="95" data-suffix="%">0%</span></strong>Akurasi Deteksi</div>
        <div class="hero-dot"></div>
        <div class="hero-stat"><strong>&lt;3s</strong>Waktu Analisis</div>
         <div class="hero-stat"><strong><span data-count="28" data-suffix="%">28.95%</span></strong>Suhu</div>
        <div class="hero-dot"></div>
         <div class="hero-stat"><strong><span data-count="86" data-suffix="%">86%</span></strong>Kelembapan</div>
        <div class="hero-dot"></div>
      </div>
    </div>
    {{-- <div class="hero-badge-bar">
      <div class="status-dot"></div>
      <div class="hero-badge-text">CAPSTONE PROJECT · DUNCHILL 2026</div>
      <div class="hero-badge-sep"></div>
      <a href="#" class="hero-login-btn">🔐 Login ke Sistem <svg width="13" height="13" fill="none" viewBox="0 0 24 24"><path d="M5 12h14M13 6l6 6-6 6" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></a>
    </div> --}}
  </div>
</section>

<!-- FITUR -->
<section class="fitur-section" id="fitur" style="padding:72px 0 0">
  <div style="text-align:center;max-width:600px;margin:0 auto;padding:0 48px 60px">
    <p class="section-badge reveal">Fitur Utama</p>
    <h2 class="section-title reveal delay-1">Teknologi <strong>Terdepan</strong> untuk<br>Perkebunan <strong>Sawit Anda</strong></h2>
  </div>

  <!-- Deteksi AI -->
  <div class="fitur-block reveal">
    <img class="fitur-block-img" src="/img/background/dashboard.png" alt="Deteksi AI">
    <div>
      {{-- <div class="fitur-block-badge">🔬 01</div> --}}
      <h3 class="fitur-block-title">Deteksi AI</h3>
      <div class="fitur-tags">
        <span class="fitur-tag"> YOLO Model</span>
        <span class="fitur-tag"> &lt;3 Detik</span>
        <span class="fitur-tag">95% Akurasi</span>
        <span class="fitur-tag"> Upload Foto</span>
      </div>
    </div>
  </div>

  <!-- Dashboard & Laporan -->
  <div class="fitur-block reverse reveal">
    <img class="fitur-block-img" src="/img/background/ano.jpg" alt="Dashboard Laporan">
    <div>
      {{-- <div class="fitur-block-badge">📊 02</div> --}}
      <h3 class="fitur-block-title">Dashboard & Laporan</h3>
      <div class="fitur-tags">
        <span class="fitur-tag"> Grafik & Statistik</span>
        <span class="fitur-tag"> Ekspor PDF</span>
        <span class="fitur-tag"> Riwayat Deteksi</span>
      </div>
    </div>
  </div>

  <!-- Multi-Role -->
  <div class="fitur-block reveal">
    <img class="fitur-block-img" src="/img/background/role.png" alt="Multi Role">
    <div>
      {{-- <div class="fitur-block-badge">👥 03</div> --}}
