<script>
document.addEventListener('DOMContentLoaded', () => {

  // LOADER
  const loader = document.getElementById('loader');
  window.addEventListener('load', () => {
    setTimeout(() => loader.classList.add('hidden'), 2000);
  });

  // NAVBAR & SCROLL TOP
  const navbar = document.querySelector('.navbar');
  const scrollTopBtn = document.querySelector('.scroll-top');
  window.addEventListener('scroll', () => {
    const sy = window.scrollY;
    navbar.classList.toggle('scrolled', sy > 60);
    scrollTopBtn.classList.toggle('visible', sy > 400);
    const heroImg = document.querySelector('.hero-img');
    if (heroImg) heroImg.style.transform = `translateY(${sy * 0.35}px)`;
  }, { passive: true });
  scrollTopBtn.addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));

  // SCROLL REVEAL
  const revealEls = document.querySelectorAll('.reveal, .reveal-left, .reveal-right');
  const obs = new IntersectionObserver(entries => {
    entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); obs.unobserve(e.target); }});
  }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });
  revealEls.forEach(el => obs.observe(el));

  // TABS
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
    });
  });

  // COUNTER
  document.querySelectorAll('[data-count]').forEach(el => {
    const cobs = new IntersectionObserver(entries => {
      if (entries[0].isIntersecting) {
        const target = parseInt(el.dataset.count), sfx = el.dataset.suffix || '';
        let n = 0; const step = Math.ceil(target / 60);
        const t = setInterval(() => { n = Math.min(n + step, target); el.textContent = n + sfx; if (n >= target) clearInterval(t); }, 18);
        cobs.unobserve(el);
      }
    }, { threshold: 0.5 });
    cobs.observe(el);
  });

  // TILT on cards
  document.querySelectorAll('.fitur-card, .tim-card, .manfaat-card').forEach(card => {
    card.addEventListener('mousemove', e => {
      const r = card.getBoundingClientRect();
      const rx = ((e.clientY - r.top) / r.height - .5) * -4;
      const ry = ((e.clientX - r.left) / r.width - .5) * 4;
      card.style.transform = `perspective(700px) rotateX(${rx}deg) rotateY(${ry}deg) translateY(-6px)`;
    });
    card.addEventListener('mouseleave', () => { card.style.transform = ''; });
  });

});
</script>

